    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main message area ── */
.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #e0e0e0;
    transition: width 0.2s ease;
}

    .message-area.expanded {
        width: 80%;
    }

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

    .message-header h2 {
        margin: 0;
        font-size: 1.1rem;
    }

    .message-header p {
        margin: 4px 0 0;
        font-size: 0.8rem;
        color: #616061;
    }

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #888;
    font-size: 1.1rem;
}

/* ── Message list ── */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    color: #888;
    padding: 8px;
    font-size: 0.85rem;
}

.message-bubble {
    padding: 8px 12px;
    margin-bottom: 4px;
    border-radius: 6px;
    position: relative;
    transition: background 0.1s;
}

    .message-bubble:hover {
        background: #f8f8f8;
    }

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    font-size: 0.8rem;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    background: #f0f0f0;
    cursor: pointer;
    transition: background 0.15s;
}

    .reaction-badge:hover {
        background: #dce8fb;
        border-color: #1d9bd1;
    }

/* ── Thread link ── */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0 0;
    font-weight: 600;
}

    .thread-link:hover {
        text-decoration: underline;
    }

/* ── Hover actions ── */
.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

    .action-btn:hover {
        background: #f0f0f0;
    }

/* ── Emoji picker ── */
.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 20;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.3rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

    .emoji-option:hover {
        background: #f0f0f0;
    }

/* ── Message input ── */
.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

    .message-input-area textarea {
        flex: 1;
        resize: none;
        border: 1px solid #ccc;
        border-radius: 6px;
        padding: 8px 12px;
        font-size: 0.9rem;
        font-family: inherit;
        outline: none;
        transition: border-color 0.15s;
    }

        .message-input-area textarea:focus {
            border-color: #1d9bd1;
        }

.send-btn {
    padding: 8px 20px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    align-self: flex-end;
    transition: background 0.15s;
}

    .send-btn:hover:not(:disabled) {
        background: #005e45;
    }

    .send-btn:disabled {
        opacity: 0.5;
        cursor: not-allowed;
    }

/* ── Thread panel ── */
.thread-panel {
    width: 25%;
    min-width: 260px;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

    .thread-header h3 {
        margin: 0;
        font-size: 1rem;
    }

.close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #616061;
    padding: 4px 8px;
    border-radius: 4px;
}

    .close-btn:hover {
        background: #f0f0f0;
    }

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 6px 0;
}
