+@code {
+    private const int PageSize = 30;
+    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];
+
+    // Data
+    private List<Channel>? _channels;
+    private List<Message>? _messages;
+    private List<Message>? _threadMessages;
+    private Dictionary<int, ThreadSummary> _threadSummaries = new();
+
+    // State
+    private int? _activeChannelId;
+    private Channel? _activeChannel;
+    private int _skip;
+    private bool _loadingMore;
+    private bool _allLoaded;
+    private string _newMessage = "";
+    private string _threadReply = "";
+    private int? _hoveredMessageId;
+    private int? _emojiPickerMessageId;
+
+    // Thread state
+    private bool _threadOpen;
+    private Message? _threadRootMessage;
+
+    // Element refs
+    private ElementReference _messageListRef;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _channels = await ChatService.GetChannelsAsync();
+        if (_channels.Count > 0)
+        {
+            await SelectChannelAsync(_channels[0]);
+        }
+    }
+
+    // ── Channel selection ──
+
+    private async Task SelectChannelAsync(Channel channel)
+    {
+        if (channel.Id == _activeChannelId) return;
+
+        _activeChannelId = channel.Id;
+        _activeChannel = channel;
+        _skip = 0;
+        _allLoaded = false;
+        _messages = new();
+        _threadSummaries = new();
+        CloseThread();
+
+        await LoadMessagesAsync();
+        await ChatService.MarkChannelReadAsync(channel.Id);
+
+        // Update local unread count to zero
+        _channels = _channels?.Select(c => c.Id == channel.Id ? c with { UnreadCount = 0 } : c).ToList();
+
+        await ScrollToBottomAsync();
+    }
+
+    // ── Message loading ──
+
+    private async Task LoadMessagesAsync()
+    {
+        if (_activeChannelId is null) return;
+
+        var batch = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
+        if (batch.Count < PageSize) _allLoaded = true;
+
+        _messages = batch.Concat(_messages ?? []).ToList();
+        _skip += batch.Count;
+
+        await BuildThreadSummariesAsync();
+    }
+
+    private async Task BuildThreadSummariesAsync()
+    {
+        if (_messages is null) return;
+
+        // Identify thread-root messages: messages that have replies pointing to them.
+        var rootIds = _messages
+            .Where(m => m.ReplyToId is not null)
+            .Select(m => m.ReplyToId!.Value)
+            .Distinct()
+            .ToHashSet();
+
+        foreach (var rootId in rootIds)
+        {
+            if (_threadSummaries.ContainsKey(rootId)) continue;
+
+            var thread = await ChatService.GetThreadAsync(rootId);
+            if (thread.Count > 0)
+            {
+                _threadSummaries[rootId] = new ThreadSummary(
+                    rootId,
+                    thread.Count,
+                    thread.Max(t => t.SentAt));
+            }
+        }
+
+        // Also include roots that are already known thread starters (they might have
+        // replies that were not fetched in the current page).
+        foreach (var msg in _messages.Where(m => m.ReplyToId is null))
+        {
+            if (_threadSummaries.ContainsKey(msg.Id)) continue;
+
+            var thread = await ChatService.GetThreadAsync(msg.Id);
+            if (thread.Count > 0)
+            {
+                _threadSummaries[msg.Id] = new ThreadSummary(
+                    msg.Id,
+                    thread.Count,
+                    thread.Max(t => t.SentAt));
+            }
+        }
+    }
+
+    private async Task HandleScrollAsync()
+    {
+        if (_loadingMore || _allLoaded) return;
+
+        var scrollTop = await JS.InvokeAsync<double>("chatInterop.getScrollTop", _messageListRef);
+        if (scrollTop < 80)
+        {
+            _loadingMore = true;
+            StateHasChanged();
+
+            var prevHeight = await JS.InvokeAsync<double>("chatInterop.getScrollHeight", _messageListRef);
+            await LoadMessagesAsync();
+            StateHasChanged();
+
+            // Restore scroll position so the view doesn't jump
+            await Task.Delay(50);
+            var newHeight = await JS.InvokeAsync<double>("chatInterop.getScrollHeight", _messageListRef);
+            await JS.InvokeVoidAsync("chatInterop.setScrollTop", _messageListRef, newHeight - prevHeight);
+
+            _loadingMore = false;
+        }
+    }
+
+    // ── Sending messages ──
+
+    private async Task SendMainMessageAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;
+
+        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
+        _messages ??= new();
+        _messages.Add(sent);
+        _newMessage = "";
+        await ScrollToBottomAsync();
+    }
+
+    private async Task HandleMainKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendMainMessageAsync();
+        }
+    }
+
+    // ── Thread ──
+
+    private async Task OpenThreadAsync(Message rootMessage)
+    {
+        _threadRootMessage = rootMessage;
+        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
+        _threadOpen = true;
+        _emojiPickerMessageId = null;
+    }
+
+    private void CloseThread()
+    {
+        _threadOpen = false;
+        _threadRootMessage = null;
+        _threadMessages = null;
+        _threadReply = "";
+    }
+
+    private async Task SendThreadReplyAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_threadReply) || _threadRootMessage is null || _activeChannelId is null) return;
+
+        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReply.Trim(), _threadRootMessage.Id);
+        _threadMessages ??= new();
+        _threadMessages.Add(reply);
+        _threadReply = "";
+
+        // Update thread summary
+        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
+            _threadRootMessage.Id,
+            _threadMessages.Count,
+            reply.SentAt);
+    }
+
+    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    // ── Reactions ──
+
+    private async Task ToggleReactionAsync(int messageId, string emoji)
+    {
+        await ChatService.AddReactionAsync(messageId, emoji);
+        _emojiPickerMessageId = null;
+
+        // Refresh the affected message in main list or thread
+        if (_activeChannelId is not null && _messages is not null)
+        {
+            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip);
+            _messages = refreshed;
+        }
+
+        if (_threadRootMessage is not null)
+        {
+            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
+        }
+    }
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    // ── Helpers ──
+
+    private async Task ScrollToBottomAsync()
+    {
+        await Task.Delay(50);
+        try
+        {
+            await JS.InvokeVoidAsync("chatInterop.scrollToBottom", _messageListRef);
+        }
+        catch
+        {
+            // Element may not be rendered yet
+        }
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
+
+        return diff.TotalSeconds switch
+        {
+            < 60 => "just now",
+            < 3600 => $"{(int)diff.TotalMinutes} min ago",
+            < 86400 => $"{(int)diff.TotalHours}h ago",
+            < 604800 => $"{(int)diff.TotalDays}d ago",
+            _ => sentAt.ToString("MMM d, yyyy")
+        };
+    }
+
+    private static string Truncate(string text, int maxLength) =>
+        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
+}
