+        await BuildThreadSummariesAsync();
+    }
+
+    private async Task BuildThreadSummariesAsync()
+    {
+        if (_messages is null) return;
+
+        // Identify thread-root messages: messages that have replies pointing to them.
+        var rootIds = _messages
+            .Where(m => m.ReplyToId is not null)
+            .Select(m => m.ReplyToId!.Value)
+            .Distinct()
+            .ToHashSet();
+
+        foreach (var rootId in rootIds)
+        {
+            if (_threadSummaries.ContainsKey(rootId)) continue;
+
+            var thread = await ChatService.GetThreadAsync(rootId);
+            if (thread.Count > 0)
+            {
+                _threadSummaries[rootId] = new ThreadSummary(
+                    rootId,
+                    thread.Count,
+                    thread.Max(t => t.SentAt));
+            }
+        }
+
+        // Also include roots that are already known thread starters (they might have
+        // replies that were not fetched in the current page).
+        foreach (var msg in _messages.Where(m => m.ReplyToId is null))
+        {
+            if (_threadSummaries.ContainsKey(msg.Id)) continue;
+
+            var thread = await ChatService.GetThreadAsync(msg.Id);
+            if (thread.Count > 0)
+            {
+                _threadSummaries[msg.Id] = new ThreadSummary(
+                    msg.Id,
+                    thread.Count,
+                    thread.Max(t => t.SentAt));
+            }
+        }
+    }
+
+    private async Task HandleScrollAsync()
+    {
+        if (_loadingMore || _allLoaded) return;
+
+        var scrollTop = await JS.InvokeAsync<double>("chatInterop.getScrollTop", _messageListRef);
+        if (scrollTop < 80)
+        {
+            _loadingMore = true;
+            StateHasChanged();
+
+            var prevHeight = await JS.InvokeAsync<double>("chatInterop.getScrollHeight", _messageListRef);
+            await LoadMessagesAsync();
+            StateHasChanged();
+
+            // Restore scroll position so the view doesn't jump
+            await Task.Delay(50);
+            var newHeight = await JS.InvokeAsync<double>("chatInterop.getScrollHeight", _messageListRef);
+            await JS.InvokeVoidAsync("chatInterop.setScrollTop", _messageListRef, newHeight - prevHeight);
+
+            _loadingMore = false;
+        }
+    }
+
+    // ── Sending messages ──
+
+    private async Task SendMainMessageAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;
+
+        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
+        _messages ??= new();
+        _messages.Add(sent);
+        _newMessage = "";
+        await ScrollToBottomAsync();
+    }
+
+    private async Task HandleMainKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendMainMessageAsync();
+        }
+    }
+
+    // ── Thread ──
+
+    private async Task OpenThreadAsync(Message rootMessage)
+    {
+        _threadRootMessage = rootMessage;
+        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
+        _threadOpen = true;
+        _emojiPickerMessageId = null;
+    }
+
+    private void CloseThread()
+    {
+        _threadOpen = false;
+        _threadRootMessage = null;
+        _threadMessages = null;
+        _threadReply = "";
+    }
+
+    private async Task SendThreadReplyAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_threadReply) || _threadRootMessage is null || _activeChannelId is null) return;
+
+        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReply.Trim(), _threadRootMessage.Id);
+        _threadMessages ??= new();
+        _threadMessages.Add(reply);
+        _threadReply = "";
+
+        // Update thread summary
+        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
+            _threadRootMessage.Id,
+            _threadMessages.Count,
+            reply.SentAt);
+    }
+
+    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    // ── Reactions ──
+
+    private async Task ToggleReactionAsync(int messageId, string emoji)
+    {
+        await ChatService.AddReactionAsync(messageId, emoji);
+        _emojiPickerMessageId = null;
+
+        // Refresh the affected message in main list or thread
+        if (_activeChannelId is not null && _messages is not null)
+        {
+            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip);
+            _messages = refreshed;
+        }
+
+        if (_threadRootMessage is not null)
+        {
+            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
+        }
+    }
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    // ── Helpers ──
+
+    private async Task ScrollToBottomAsync()
+    {
+        await Task.Delay(50);
+        try
+        {
+            await JS.InvokeVoidAsync("chatInterop.scrollToBottom", _messageListRef);
+        }
+        catch
+        {
+            // Element may not be rendered yet
+        }
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
+
+        return diff.TotalSeconds switch
+        {
+            < 60 => "just now",
+            < 3600 => $"{(int)diff.TotalMinutes} min ago",
+            < 86400 => $"{(int)diff.TotalHours}h ago",
+            < 604800 => $"{(int)diff.TotalDays}d ago",
+            _ => sentAt.ToString("MMM d, yyyy")
+        };
+    }
+
+    private static string Truncate(string text, int maxLength) =>
+        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
+}
+

toolArgs.file_text:
/* ── Layout ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
    background: #fff;
}

/* ── Sidebar ── */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

    .sidebar-header h3 {
        margin: 0;
        color: #fff;
        font-size: 1.1rem;
    }

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 6px 16px;
    cursor: pointer;
    position: relative;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

    .channel-item:hover {
        background: rgba(255, 255, 255, 0.08);
    }

    .channel-item.active {
        background: rgba(255, 255, 255, 0.15);
        border-left-color: #fff;
    }

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main message area ── */
.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #e0e0e0;
    transition: width 0.2s ease;
}

    .message-area.expanded {
        width: 80%;
    }

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

    .message-header h2 {
        margin: 0;
        font-size: 1.1rem;
    }

    .message-header p {
        margin: 4px 0 0;
        font-size: 0.8rem;
        color: #616061;
    }

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #888;
    font-size: 1.1rem;
}

/* ── Message list ── */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    color: #888;
    padding: 8px;
    font-size: 0.85rem;
}

.message-bubble {
    padding: 8px 12px;
    margin-bottom: 4px;
    border-radius: 6px;
    position: relative;
    transition: background 0.1s;
}

    .message-bubble:hover {
        background: #f8f8f8;
    }

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    font-size: 0.8rem;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    background: #f0f0f0;
    cursor: pointer;
    transition: background 0.15s;
}

    .reaction-badge:hover {
        background: #dce8fb;
        border-color: #1d9bd1;
    }

/* ── Thread link ── */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0 0;
    font-weight: 600;
}

    .thread-link:hover {
        text-decoration: underline;
    }

/* ── Hover actions ── */
.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

    .action-btn:hover {
        background: #f0f0f0;
    }

/* ── Emoji picker ── */
.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 20;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.3rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

    .emoji-option:hover {
        background: #f0f0f0;
    }

/* ── Message input ── */
.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

    .message-input-area textarea {
        flex: 1;
        resize: none;
        border: 1px solid #ccc;
        border-radius: 6px;
        padding: 8px 12px;
        font-size: 0.9rem;
        font-family: inherit;
        outline: none;
        transition: border-color 0.15s;
    }

        .message-input-area textarea:focus {
            border-color: #1d9bd1;
        }

.send-btn {
    padding: 8px 20px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    align-self: flex-end;
    transition: background 0.15s;
}

    .send-btn:hover:not(:disabled) {
        background: #005e45;
    }

    .send-btn:disabled {
        opacity: 0.5;
        cursor: not-allowed;
    }

/* ── Thread panel ── */
.thread-panel {
    width: 25%;
    min-width: 260px;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

    .thread-header h3 {
        margin: 0;
        font-size: 1rem;
    }

.close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #616061;
    padding: 4px 8px;
    border-radius: 4px;
}

    .close-btn:hover {
        background: #f0f0f0;
    }

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 6px 0;
}

